import jwt
import json
from typing import Dict, Any, Optional

def decode_jwt(token: str, secret: str, algorithms: list = None) -> Dict[str, Any]:
    """
    Decode and verify JWT token for debugging purposes.
    
    Args:
        token (str): The JWT token to decode
        secret (str): The secret used to verify the token
        algorithms (list): List of allowed algorithms (required for security)
    
    Returns:
        dict: Decoded token payload
    
    Raises:
        jwt.InvalidTokenError: If token is invalid
        jwt.ExpiredSignatureError: If token has expired
        Exception: For other errors
    """
    if not algorithms:
        algorithms = ['HS256']
    
    try:
        # Decode and verify the token
        decoded = jwt.decode(
            token,
            secret,
            algorithms=algorithms,
            options={"verify_signature": True, "verify_exp": True}
        )
        return decoded
    except jwt.InvalidTokenError as e:
        raise Exception(f"Invalid token: {str(e)}")
    except jwt.ExpiredSignatureError:
        raise Exception("Token has expired")
    except Exception as e:
        raise Exception(f"Error decoding token: {str(e)}")

def debug_jwt(token: str, secret: str, algorithms: list = None) -> None:
    """
    Debug JWT token by printing its contents.
    
    Args:
        token (str): The JWT token to debug
        secret (str): The secret used to verify the token
        algorithms (list): List of allowed algorithms
    """
    try:
        payload = decode_jwt(token, secret, algorithms)
        print("=== JWT DEBUG INFO ===")
        print(f"Token: {token}")
        print("Payload:")
        print(json.dumps(payload, indent=2, default=str))
        print("======================")
    except Exception as e:
        print(f"Error debugging token: {str(e)}")

